class Solution {
public:
    int findTheLongestSubstring(string s) {
        int n = s.size();
        int res = 0;
        int mask = 0;
        unordered_map<int, int> mp;
        mp[0] = -1;
        int cur = 0;
        for (int i = 0; i < n; i++) {
            if (s[i] == 'a' || s[i] == 'e' || s[i] == 'i' || s[i] == 'o' || s[i] == 'u') {
                cur ^= (1 << (s[i] - 'a'));
            }
            if (mp.find(cur) != mp.end()) {
                res = max(res, i - mp[cur]);
            } else {
                mp[cur] = i;
            }
        }
        return res;
    }
};
